class Solution:
    def hammingDistance(self, x: int, y: int) -> int:
        return (x ^ y).bit_count()

solutions.cpp:
class Solution {
public:
    int hammingDistance(int x, int y) {
        return __builtin_popcount(x ^ y);
    }
};

solutions.c:
int hammingDistance(int x, int y) {
    unsigned v = x ^ y, c = 0;
    while(v){ c += v & 1; v >>= 1; }
    return c;
}
